import type { Window } from "./Window";
export type Input = {
    /** Window object from `list_apps()` or `list_windows()` to scroll. */
    window: Window;
    /** X coordinate in the window screenshot to scroll from. */
    x: number;
    /** Y coordinate in the window screenshot to scroll from. */
    y: number;
    /** Screenshot id from the latest `get_window_state()` response for coordinate input. */
    screenshotId?: string;
    /** Horizontal scroll delta; negative means left, positive means right. */
    scrollX: number;
    /** Vertical scroll delta; negative means up, positive means down. */
    scrollY: number;
};
export type Return = Promise<void>;
/** Scroll by a delta from a specific coordinate in the window screenshot. */
export type Function = (input: Input) => Return;
